  <HEADER encrypted="1" encrypted_ver="1" build="0.0704.1001.0000.13.0" user="user" computer="WIN-856EDCD152U" date="2025.08.18 20'08'45" map_xs="110" map_ys="110" north_angle="0" extra_map_edge="1" tileset="bavarian" environment="Bavarian_Final" players="6" name="Поле битвы" id="the_battlefield" style="0" description="Члены команды начнут рядом друг с другом на этой богатой на ресурсы карте, а центральный игрок из каждой команды окажется под защитой каменного утеса. Группы кондотьеров обороняют несколько нейтральных построек, а также по два города для экспансии на игрока. Однако в центральной долине живут враждебные падальщики." enable_dominance="1" preview_image_ext="tga" version="12" allowable_game_styles="4294967295" default_game_style="-1" victory="0" elimination="1" allies="11" living_world_bird="0" force_rush_rules_disable="0" does_override_teamstyle="0" teamstyle_override_value="0" starts_required="0" starts_no_pick="0" show_all_villages="1" generate_script="0" num_villages="0" num_special="0" num_villages_override="12" num_special_override="12">
